export const buscarOfertasPromocao = async () => {
  try {
  
    const response = await fetch('http://localhost:3001/api/promocao_10'); 
    
    if (!response.ok) {
      throw new Error('Erro ao buscar ofertas');
    }
    
    const dados = await response.json();
    return dados;
  } catch (error) {
    console.error("Erro na requisição das ofertas:", error);
    return [];
  }
};
app.get('/api/estoque', (req, res) => {
  const query = "SELECT * FROM estoque.promocao_10";
  db.query(query, (err, results) => {
    if (err) return res.status(500).send(err);
    res.json(results);
  });
});
